mapper.select:
SELECT SESSION_ID AS sessionId, USER_ID AS userId, DOCTOR_ID AS doctorId, STATUS AS status, LAST_MESSAGE AS lastMessage, LAST_MESSAGE_AT AS lastMessageAt, MESSAGE_COUNT AS messageCount, RATING AS rating, FEEDBACK AS feedback, STARTED_AT AS startedAt, ENDED_AT AS endedAt FROM CONSULTATION_SESSIONS WHERE USER_ID = #{userId} AND DEL_FLAG = 0
AND STATUS = #{status}
ORDER BY COALESCE(LAST_MESSAGE_AT, STARTED_AT) DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM CONSULTATION_SESSIONS
WHERE USER_ID = #{userId} AND DEL_FLAG = 0

    AND STATUS = #{status}
